"use client";

import { useEffect, useMemo, useState } from "react";

type IptuFormData = {
  numero: string;
  ano: string;
  dataEmissao: string;
  nomeResponsavel: string;
  nomeFantasia: string;
  cpfCnpj: string;
  enderecoResponsavel: string;
  bairroResponsavel: string;
  cidadeResponsavel: string;
  cepResponsavel: string;
  enderecoImovel: string;
  areaTerreno: string;
  areaConstruida: string;
  responsavelNome: string;
  responsavelCargo: string;
  responsavelPortaria: string;
};

type SavedDeclaration = {
  id: string;
  createdAt: string;
  form: IptuFormData;
};

const STORAGE_KEY = "iptu:declaracoes:v1";

const CREST_SRC = "data:image/png;base64,";
const FOOTER_SRC = "data:image/png;base64,";

function getTodayISO() {
  return new Date().toISOString().split("T")[0];
}

const initialForm: IptuFormData = {
  numero: "",
  ano: String(new Date().getFullYear()),
  dataEmissao: getTodayISO(),
  nomeResponsavel: "",
  nomeFantasia: "",
  cpfCnpj: "",
  enderecoResponsavel: "",
  bairroResponsavel: "",
  cidadeResponsavel: "ELDORADO DO CARAJÁS/PA",
  cepResponsavel: "68524-000",
  enderecoImovel: "",
  areaTerreno: "",
  areaConstruida: "",
  responsavelNome: "Wigo De Sousa Almeida",
  responsavelCargo: "Diretor de Arrecadação Municipal",
  responsavelPortaria: "Port. Nº 20/2025 - GPM",
};

function formatDateLong(dateValue: string) {
  if (!dateValue) return "";

  const [year, month, day] = dateValue.split("-").map(Number);
  if (!year || !month || !day) return "";

  const date = new Date(year, month - 1, day);

  return new Intl.DateTimeFormat("pt-BR", {
    day: "numeric",
    month: "long",
    year: "numeric",
  }).format(date);
}

function addDaysISO(dateValue: string, days: number) {
  if (!dateValue) return "";

  const [year, month, day] = dateValue.split("-").map(Number);
  if (!year || !month || !day) return "";

  const date = new Date(year, month - 1, day);
  date.setDate(date.getDate() + days);

  const adjustedYear = date.getFullYear();
  const adjustedMonth = String(date.getMonth() + 1).padStart(2, "0");
  const adjustedDay = String(date.getDate()).padStart(2, "0");

  return `${adjustedYear}-${adjustedMonth}-${adjustedDay}`;
}

function clean(value: string, fallback = "________________") {
  const trimmed = value.trim();
  return trimmed || fallback;
}

function normalizeText(value: string) {
  return value.replace(/\s+/g, " ").replace(/\s+,/g, ",").trim();
}

function upperInput(value: string) {
  return value.toUpperCase();
}

export default function IptuPage() {
  const [form, setForm] = useState<IptuFormData>(initialForm);
  const [history, setHistory] = useState<SavedDeclaration[]>([]);

  useEffect(() => {
    try {
      const raw = localStorage.getItem(STORAGE_KEY);
      if (raw) {
        setHistory(JSON.parse(raw));
      }
    } catch {
      setHistory([]);
    }
  }, []);

  function persistHistory(nextHistory: SavedDeclaration[]) {
    setHistory(nextHistory);
    localStorage.setItem(STORAGE_KEY, JSON.stringify(nextHistory));
  }

  function updateField(field: keyof IptuFormData, value: string) {
    setForm((prev) => ({
      ...prev,
      [field]: field === "dataEmissao" ? value : upperInput(value),
    }));
  }

  function saveDeclaration() {
    const id = `${form.numero || "sem-numero"}-${form.ano || new Date().getFullYear()}-${Date.now()}`;

    const nextItem: SavedDeclaration = {
      id,
      createdAt: new Date().toISOString(),
      form: { ...form },
    };

    const nextHistory = [nextItem, ...history].slice(0, 80);
    persistHistory(nextHistory);
  }

  function imprimirSalvar() {
    saveDeclaration();

    const printArea = document.getElementById("printArea");

    if (!printArea) {
      window.print();
      return;
    }

    const oldFrame = document.getElementById("iptu-print-frame");
    if (oldFrame) {
      oldFrame.remove();
    }

    const frame = document.createElement("iframe");
    frame.id = "iptu-print-frame";
    frame.style.position = "fixed";
    frame.style.right = "0";
    frame.style.bottom = "0";
    frame.style.width = "0";
    frame.style.height = "0";
    frame.style.border = "0";
    frame.style.opacity = "0";
    frame.style.pointerEvents = "none";
    document.body.appendChild(frame);

    const frameWindow = frame.contentWindow;
    const frameDocument = frame.contentDocument || frameWindow?.document;

    if (!frameWindow || !frameDocument) {
      window.print();
      return;
    }

    const pageHtml = printArea.outerHTML;

    const styleLinks = Array.from(
      document.head.querySelectorAll('link[rel="stylesheet"], style')
    )
      .map((node) => node.outerHTML)
      .join("\n");

    frameDocument.open();
    frameDocument.write(`<!doctype html>
<html>
  <head>
    <meta charset="utf-8" />
    <base href="${window.location.origin}" />
    ${styleLinks}
    <style>
      @page {
        size: A4;
        margin: 0;
      }

      html,
      body {
        width: 210mm;
        height: 297mm;
        margin: 0;
        padding: 0;
        background: white;
        overflow: hidden;
      }

      body {
        -webkit-print-color-adjust: exact !important;
        print-color-adjust: exact !important;
      }

      #printArea {
        position: relative !important;
        width: 210mm !important;
        height: 297mm !important;
        margin: 0 !important;
        padding: 7mm 24mm 34mm 24mm !important;
        box-sizing: border-box !important;
        background: white !important;
        box-shadow: none !important;
        border: none !important;
        border-radius: 0 !important;
        overflow: hidden !important;
        -webkit-print-color-adjust: exact !important;
        print-color-adjust: exact !important;
      }

      #printArea img {
        -webkit-print-color-adjust: exact !important;
        print-color-adjust: exact !important;
      }
    </style>
  </head>
  <body>
    ${pageHtml}
  </body>
</html>`);
    frameDocument.close();

    const printFrame = () => {
      const images: HTMLImageElement[] = Array.from(frameDocument.images);

      Promise.all(
        images.map((image): Promise<void> => {
          if (image.complete) return Promise.resolve();

          if (typeof image.decode === "function") {
            return image.decode().catch(() => undefined);
          }

          return new Promise<void>((resolve) => {
            image.onload = () => resolve();
            image.onerror = () => resolve();
          });
        })
      ).then(() => {
        window.setTimeout(() => {
          frameWindow.focus();
          frameWindow.print();

          window.setTimeout(() => {
            frame.remove();
          }, 1500);
        }, 250);
      });
    };

    if (frameDocument.readyState === "complete") {
      printFrame();
    } else {
      frame.onload = printFrame;
      window.setTimeout(printFrame, 800);
    }
  }

  function novaDeclaracao() {
    setForm({
      ...initialForm,
      ano: String(new Date().getFullYear()),
      dataEmissao: getTodayISO(),
    });
  }

  function carregarDeclaracao(item: SavedDeclaration) {
    setForm({
      ...initialForm,
      ...item.form,
    });
  }

  function excluirDeclaracao(id: string) {
    const nextHistory = history.filter((item) => item.id !== id);
    persistHistory(nextHistory);
  }

  const dataPorExtenso = useMemo(
    () => formatDateLong(form.dataEmissao),
    [form.dataEmissao]
  );

  const validadePorExtenso = useMemo(
    () => formatDateLong(addDaysISO(form.dataEmissao, 30)),
    [form.dataEmissao]
  );

  const documentoNumero = `${clean(form.numero, "___")}/${clean(
    form.ano,
    String(new Date().getFullYear())
  )}`;

  const nomeFantasiaFinal = clean(form.nomeFantasia || form.nomeResponsavel);
  const enderecoImovelFinal = normalizeText(clean(form.enderecoImovel));

  return (
    <main className="min-h-screen bg-slate-100 text-slate-950">
      <style jsx global>{`
        @page {
          size: A4;
          margin: 0;
        }

        @media print {
          html,
          body {
            margin: 0 !important;
            padding: 0 !important;
            background: white !important;
          }

          body * {
            visibility: hidden !important;
          }

          #printArea,
          #printArea * {
            visibility: visible !important;
          }

          #printArea {
            position: fixed !important;
            left: 0 !important;
            top: 0 !important;
            width: 210mm !important;
            height: 297mm !important;
            margin: 0 !important;
            padding: 7mm 24mm 34mm 24mm !important;
            box-sizing: border-box !important;
            box-shadow: none !important;
            border: none !important;
            border-radius: 0 !important;
            overflow: hidden !important;
            -webkit-print-color-adjust: exact !important;
            print-color-adjust: exact !important;
          }

          #printArea img {
            visibility: visible !important;
            -webkit-print-color-adjust: exact !important;
            print-color-adjust: exact !important;
          }

          #printFooterRoot,
          #printFooterRoot * {
            visibility: visible !important;
            display: block !important;
          }

          #printFooterRoot {
            position: fixed !important;
            left: 0 !important;
            right: auto !important;
            bottom: 0 !important;
            width: 210mm !important;
            height: 30mm !important;
            margin: 0 !important;
            padding: 0 !important;
            z-index: 999999 !important;
            overflow: hidden !important;
            pointer-events: none !important;
            -webkit-print-color-adjust: exact !important;
            print-color-adjust: exact !important;
          }

          #printFooterRoot img {
            width: 210mm !important;
            height: 30mm !important;
            object-fit: cover !important;
            object-position: bottom !important;
            display: block !important;
            -webkit-print-color-adjust: exact !important;
            print-color-adjust: exact !important;
          }

          .no-print {
            display: none !important;
          }
        }
      `}</style>

      <div className="no-print border-b border-emerald-950 bg-emerald-950 py-4 shadow-sm">
        <div className="mx-auto max-w-7xl px-6">
          <p className="text-xs font-black uppercase tracking-[0.32em] text-emerald-200">
            Prefeitura Municipal de Eldorado do Carajás
          </p>
          <p className="mt-1 text-sm font-semibold text-white/80">
            Departamento de Arrecadação Fazendária - DAF
          </p>
        </div>
      </div>

      <div className="mx-auto grid max-w-7xl gap-6 px-6 py-8 lg:grid-cols-[430px_1fr]">
        <section className="no-print rounded-3xl border border-slate-200 bg-white p-6 shadow-sm">
          <h1 className="text-3xl font-black tracking-tight">Não Recolhimento de IPTU</h1>
          <p className="mt-2 text-sm leading-6 text-slate-600">
            Preencha os dados do responsável e do imóvel. A validade é calculada automaticamente para 30 dias após a emissão.
          </p>

          <div className="mt-6 space-y-6">
            <div>
              <h2 className="mb-3 text-sm font-black uppercase tracking-[0.18em] text-emerald-800">
                Controle
              </h2>
              <div className="grid gap-3 sm:grid-cols-3">
                <input
                  className="rounded-xl border border-slate-300 p-3 text-sm"
                  placeholder="Nº"
                  value={form.numero}
                  onChange={(e) => updateField("numero", e.target.value)}
                />
                <input
                  className="rounded-xl border border-slate-300 p-3 text-sm"
                  placeholder="Ano"
                  value={form.ano}
                  onChange={(e) => updateField("ano", e.target.value)}
                />
                <input
                  type="date"
                  className="rounded-xl border border-slate-300 p-3 text-sm"
                  value={form.dataEmissao}
                  onChange={(e) => updateField("dataEmissao", e.target.value)}
                />
              </div>
            </div>

            <div>
              <h2 className="mb-3 text-sm font-black uppercase tracking-[0.18em] text-emerald-800">
                Responsável / Contribuinte
              </h2>
              <div className="space-y-3">
                <input
                  className="w-full rounded-xl border border-slate-300 p-3 text-sm"
                  placeholder="Nome / Nome empresarial"
                  value={form.nomeResponsavel}
                  onChange={(e) => updateField("nomeResponsavel", e.target.value)}
                />
                <input
                  className="w-full rounded-xl border border-slate-300 p-3 text-sm"
                  placeholder="Nome fantasia (se vazio, repete o nome)"
                  value={form.nomeFantasia}
                  onChange={(e) => updateField("nomeFantasia", e.target.value)}
                />
                <input
                  className="w-full rounded-xl border border-slate-300 p-3 text-sm"
                  placeholder="CPF/CNPJ"
                  value={form.cpfCnpj}
                  onChange={(e) => updateField("cpfCnpj", e.target.value)}
                />
                <input
                  className="w-full rounded-xl border border-slate-300 p-3 text-sm"
                  placeholder="Endereço do responsável"
                  value={form.enderecoResponsavel}
                  onChange={(e) => updateField("enderecoResponsavel", e.target.value)}
                />
                <div className="grid gap-3 sm:grid-cols-3">
                  <input
                    className="rounded-xl border border-slate-300 p-3 text-sm"
                    placeholder="Bairro"
                    value={form.bairroResponsavel}
                    onChange={(e) => updateField("bairroResponsavel", e.target.value)}
                  />
                  <input
                    className="rounded-xl border border-slate-300 p-3 text-sm"
                    placeholder="Cidade/UF"
                    value={form.cidadeResponsavel}
                    onChange={(e) => updateField("cidadeResponsavel", e.target.value)}
                  />
                  <input
                    className="rounded-xl border border-slate-300 p-3 text-sm"
                    placeholder="CEP"
                    value={form.cepResponsavel}
                    onChange={(e) => updateField("cepResponsavel", e.target.value)}
                  />
                </div>
              </div>
            </div>

            <div>
              <h2 className="mb-3 text-sm font-black uppercase tracking-[0.18em] text-emerald-800">
                Imóvel
              </h2>
              <textarea
                className="min-h-[120px] w-full resize-y rounded-xl border border-slate-300 p-3 text-sm leading-6"
                placeholder="Endereço completo do imóvel"
                value={form.enderecoImovel}
                onChange={(e) => updateField("enderecoImovel", e.target.value)}
              />
              <div className="mt-3 grid gap-3 sm:grid-cols-2">
                <input
                  className="rounded-xl border border-slate-300 p-3 text-sm"
                  placeholder="Área do terreno. Ex: 2.236,54"
                  value={form.areaTerreno}
                  onChange={(e) => updateField("areaTerreno", e.target.value)}
                />
                <input
                  className="rounded-xl border border-slate-300 p-3 text-sm"
                  placeholder="Área construída. Ex: 333,89"
                  value={form.areaConstruida}
                  onChange={(e) => updateField("areaConstruida", e.target.value)}
                />
              </div>
            </div>

            <div>
              <h2 className="mb-3 text-sm font-black uppercase tracking-[0.18em] text-emerald-800">
                Assinatura
              </h2>
              <div className="space-y-3">
                <input
                  className="w-full rounded-xl border border-slate-300 p-3 text-sm"
                  placeholder="Responsável"
                  value={form.responsavelNome}
                  onChange={(e) => updateField("responsavelNome", e.target.value)}
                />
                <input
                  className="w-full rounded-xl border border-slate-300 p-3 text-sm"
                  placeholder="Cargo"
                  value={form.responsavelCargo}
                  onChange={(e) => updateField("responsavelCargo", e.target.value)}
                />
                <input
                  className="w-full rounded-xl border border-slate-300 p-3 text-sm"
                  placeholder="Portaria"
                  value={form.responsavelPortaria}
                  onChange={(e) => updateField("responsavelPortaria", e.target.value)}
                />
              </div>
            </div>

            <div className="flex flex-wrap gap-3 pt-2">
              <button
                onClick={imprimirSalvar}
                className="rounded-xl bg-emerald-700 px-5 py-3 text-sm font-black text-white shadow-sm transition hover:bg-emerald-800"
              >
                IMPRIMIR/SALVAR
              </button>
              <button
                onClick={novaDeclaracao}
                className="rounded-xl bg-slate-200 px-5 py-3 text-sm font-black text-slate-700 transition hover:bg-slate-300"
              >
                Nova certidão
              </button>
            </div>
          </div>

          <div className="mt-8 border-t border-slate-200 pt-5">
            <h2 className="text-sm font-black uppercase tracking-[0.18em] text-emerald-800">
              Histórico
            </h2>
            {history.length === 0 ? (
              <p className="mt-3 text-sm text-slate-500">Nenhuma certidão salva ainda.</p>
            ) : (
              <div className="mt-3 max-h-[300px] space-y-2 overflow-auto pr-1">
                {history.map((item) => (
                  <div key={item.id} className="rounded-2xl border border-slate-200 bg-slate-50 p-3">
                    <button
                      type="button"
                      onClick={() => carregarDeclaracao(item)}
                      className="block w-full text-left"
                    >
                      <p className="text-sm font-black text-slate-900">
                        {item.form.numero || "S/N"}/{item.form.ano || "----"} - {item.form.nomeResponsavel || "Sem nome"}
                      </p>
                      <p className="mt-1 text-xs text-slate-500">
                        {new Date(item.createdAt).toLocaleString("pt-BR")}
                      </p>
                    </button>
                    <button
                      type="button"
                      onClick={() => excluirDeclaracao(item.id)}
                      className="mt-2 text-xs font-bold text-red-600 hover:text-red-700"
                    >
                      Excluir
                    </button>
                  </div>
                ))}
              </div>
            )}
          </div>
        </section>

        <section className="overflow-auto rounded-3xl border border-slate-200 bg-slate-200 p-4 shadow-sm">
          <div
            id="printArea"
            className="relative mx-auto bg-white shadow-md"
            style={{
              width: "210mm",
              height: "297mm",
              fontFamily: '"Times New Roman", Times, serif',
              color: "#000",
              overflow: "hidden",
              padding: "7mm 24mm 34mm 24mm",
              boxSizing: "border-box",
            }}
          >
            <div className="text-center">
              <img
                src={CREST_SRC}
                alt="Brasão"
                style={{ display: "block", height: "23mm", width: "auto", margin: "0 auto", objectFit: "contain" }}
              />
              <div className="mt-[1mm] text-[15pt] font-bold leading-[1.18]">
                <p>ESTADO DO PARÁ</p>
                <p>GOVERNO DE ELDORADO DO CARAJÁS</p>
                <p>CNPJ: 84.139.633/0001-75</p>
                <p>DEPARTAMENTO DE ARRECADAÇÃO FAZENDÁRIA - DAF</p>
              </div>
            </div>

            <div className="mt-[5mm] text-center">
              <p className="text-[17pt] font-bold tracking-[0.06em]">DECLARAÇÃO DE NÃO RECOLHIMENTO DE IPTU</p>
              <p className="mt-[2mm] text-[13pt] font-bold">CERTIDÃO Nº {documentoNumero}</p>
            </div>

            <div className="mt-[6mm] border border-black text-[12.6pt] leading-[1.18]">
              <div className="border-b border-black py-[1mm] text-center text-[14.5pt] font-bold">Contribuinte</div>
              <div className="space-y-[1.2mm] p-[2.5mm]">
                <p className="break-words">Nome Empresarial: <strong>{clean(form.nomeResponsavel)}</strong></p>
                <p className="break-words">Nome Fantasia: <strong>{nomeFantasiaFinal}</strong></p>
                <p className="break-words">CPF/CNPJ: <strong>{clean(form.cpfCnpj, "________________")}</strong></p>
                <p className="break-words">Endereço: <strong>{clean(form.enderecoResponsavel)}</strong></p>
                <p className="break-words">Bairro: <strong>{clean(form.bairroResponsavel)}</strong></p>
                <div className="grid grid-cols-[1fr_auto] gap-[5mm]">
                  <p className="break-words">Cidade: <strong>{clean(form.cidadeResponsavel)}</strong></p>
                  <p className="whitespace-nowrap">CEP: <strong>{clean(form.cepResponsavel, "________")}</strong></p>
                </div>
              </div>
            </div>

            <div className="mt-[9mm] text-justify text-[13.4pt] leading-[1.45]">
              <p className="indent-[16mm]">
                Certificamos, a pedido da parte interessada, que após consulta aos nossos registros, referente ao cadastro imobiliário abaixo identificado, constatamos que até a presente data não constam débitos em aberto relativos ao Imposto Predial e Territorial Urbano - IPTU, Tributos Municipais ou Créditos Administrativos vinculados ao imóvel urbano localizado na <strong>{enderecoImovelFinal}</strong>, estado do Pará.
              </p>
              <p className="mt-[4mm] indent-[16mm]">
                Área do terreno: <strong>{clean(form.areaTerreno, "________")} m²</strong> (metros quadrados). Área construída: <strong>{clean(form.areaConstruida, "________")} m²</strong> (metros quadrados).
              </p>
              <p className="mt-[4mm] indent-[16mm]">
                A presente certidão é válida por 30 (trinta) dias, com validade até <strong>{validadePorExtenso || "____ de __________ de ______"}</strong>.
              </p>
              <p className="mt-[4mm] indent-[16mm]">
                Por ser verdade, dato e assino a presente declaração.
              </p>
            </div>

            <div className="mt-[8mm] text-right text-[13.6pt]">
              Eldorado do Carajás – PA, {dataPorExtenso || "____ de __________ de ______"}.
            </div>

            <div className="absolute left-0 right-0 bottom-[30mm] text-center text-[13.8pt] leading-[1.12]">
              <div className="mx-auto mb-[3mm] w-[82mm] border-t border-black" />
              <p>{clean(form.responsavelNome, "Wigo De Sousa Almeida")}</p>
              <p>{clean(form.responsavelCargo, "Diretor de Arrecadação Municipal")}</p>
              <p>{clean(form.responsavelPortaria, "Port. Nº 20/2025 - GPM")}</p>
            </div>

            <img
              src={FOOTER_SRC}
              alt="Rodapé institucional"
              style={{
                position: "absolute",
                left: 0,
                bottom: 0,
                display: "block",
                width: "210mm",
                height: "30mm",
                objectFit: "cover",
                objectPosition: "bottom",
                zIndex: 9999,
              }}
            />
          </div>
        </section>
      </div>

      <div
        id="printFooterRoot"
        aria-hidden="true"
        style={{
          display: "none",
        }}
      >
        <img
          src={FOOTER_SRC}
          alt=""
          style={{
            width: "210mm",
            height: "30mm",
            objectFit: "cover",
            objectPosition: "bottom",
            display: "block",
          }}
        />
      </div>
    </main>
  );
}
